    pub async fn first_or_create(self, create: impl FnOnce(MetaCreateInner<'db>) -> MetaCreateInner<'db>) -> Result<MetaRecord> {
        let db = self.db.clone();
        let base_url = self.base_url.clone();
        if let Some(existing) = self.first().await? {
            return Ok(existing);
        }
        let insert_builder = create(MetaCreateInner::new(db.clone(), base_url.clone()));
        let view = insert_builder.save().await?;
        MetaQueryInner::new(db, base_url).find(view.id).await.map(|r| r.unwrap())
    }

    pub async fn update_or_create(
        self,
        on_update: impl FnOnce(MetaPatchInner<'db>) -> MetaPatchInner<'db>,
        on_create: impl FnOnce(MetaCreateInner<'db>) -> MetaCreateInner<'db>,
    ) -> Result<MetaRecord> {
        let db = self.db.clone();
        let base_url = self.base_url.clone();
        let where_sql = self.where_sql.clone();
        let binds = self.binds.clone();
        if let Some(existing) = self.first().await? {
            let mut update_builder = MetaPatchInner::new(db.clone(), base_url.clone());
            update_builder.where_sql = where_sql;
            update_builder.binds = binds;
            let update_builder = on_update(update_builder);
            update_builder.save().await?;
            return MetaQueryInner::new(db, base_url.clone()).find(existing.id.clone()).await.map(|r| r.unwrap());
        }
        let insert_builder = on_create(MetaCreateInner::new(db.clone(), base_url.clone()));
        let view = insert_builder.save().await?;
        MetaQueryInner::new(db, base_url).find(view.id).await.map(|r| r.unwrap())
    }

